changeSet.sql:
DO $$ BEGIN
CREATE TYPE user_role AS ENUM ('USER', 'ADMIN');
EXCEPTION
WHEN duplicate_object THEN null;
END $$;

DO $$ BEGIN
CREATE TYPE advertisement_status AS ENUM ('ACTIVE', 'SALE', 'CANCELLED');
EXCEPTION
WHEN duplicate_object THEN null;
END $$;

DO $$ BEGIN
CREATE TYPE product_category AS ENUM ('CAR', 'FLOWER');
EXCEPTION
WHEN duplicate_object THEN null;
END $$;

rollback.sql:
DROP TYPE IF EXISTS user_role;
DROP TYPE IF EXISTS advertisement_status;
DROP TYPE IF EXISTS product_category;
